// @vitest-environment node

/**
 * Documentation tests for the README's deep-linking section.
 *
 * task.md lists "Deep linkable URL pattern" as an explicit requirement and
 * states that "the state of the UI should be kept in the URL". The router in
 * `src/router.ts` implements this with a hash-based scheme. These tests guard
 * the *user-facing documentation* of that feature: they fail until README.md
 * documents the deep-linking behavior so a reader can discover that any folder
 * or search result is bookmarkable and shareable via URL.
 *
 * This file is pinned to the `node` environment (see the docblock above)
 * because it reads README.md from disk using `node:fs`; no DOM is required.
 */
import { describe, it, expect } from 'vitest';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';

const readmePath = fileURLToPath(new URL('../README.md', import.meta.url));
const readme = readFileSync(readmePath, 'utf8');

/** Find the 0-based offset of a level-2 section header in the README. */
function headingOffset(text: string, title: RegExp): number {
  const match = text.match(new RegExp(`^##\\s+${title.source}`, 'mi'));
  return match === null ? -1 : match.index ?? -1;
}

/** Return the body of a level-2 section (up to the next `## ` header). */
function sectionBody(text: string, title: RegExp): string {
  const start = headingOffset(text, title);
  if (start === -1) return '';
  const rest = text.slice(start);
  const nextHeader = rest.slice(1).search(/^##\s+/m);
  return nextHeader === -1 ? rest : rest.slice(0, nextHeader + 1);
}

describe('README deep-linking documentation', () => {
  describe('section presence and placement', () => {
    it('contains a "## Deep Linking" level-2 section', () => {
      expect(headingOffset(readme, /Deep Linking/i)).not.toBe(-1);
    });

    it('places the Deep Linking section between Configuration and Running Tests', () => {
      const config = headingOffset(readme, /Configuration\b/);
      const deepLinking = headingOffset(readme, /Deep Linking/i);
      const runningTests = headingOffset(readme, /Running Tests\b/);

      // Sanity: the anchors we order against must all exist.
      expect(config).not.toBe(-1);
      expect(runningTests).not.toBe(-1);
      expect(deepLinking).not.toBe(-1);

      expect(config).toBeLessThan(deepLinking);
      expect(deepLinking).toBeLessThan(runningTests);
    });
  });

  describe('explains the concept', () => {
    const body = sectionBody(readme, /Deep Linking/i);

    it('states that the current view/location is kept in the URL hash', () => {
      // The implementation uses the URL *hash* (fragment) for routing.
      expect(body).toMatch(/\burl\b/i);
      expect(body).toMatch(/\bhash\b/i);
    });

    it('notes that a location can be bookmarked or shared', () => {
      expect(body).toMatch(/bookmark|share/i);
    });
  });

  describe('documents concrete URL examples', () => {
    const body = sectionBody(readme, /Deep Linking/i);

    it('documents the root browse URL "#/browse"', () => {
      // Literally present as a code span / fenced block.
      expect(body).toContain('#/browse');
    });

    it('documents a nested folder URL "#/browse/Documents/Reports"', () => {
      expect(body).toContain('#/browse/Documents/Reports');
    });

    it('documents a scoped search URL "#/search?q=budget&path=Documents"', () => {
      expect(body).toContain('#/search?q=budget&path=Documents');
    });

    it('documents that each path segment is percent-encoded (spaces -> %20)', () => {
      expect(body).toMatch(/percent/i);
      expect(body).toContain('%20');
    });
  });
});

// @vitest-environment node

/**
 * Pure-function tests for the router's parsers and serializers.
 *
 * This file is pinned to the `node` environment (see the docblock above) on
 * purpose: the spec requires the pure helpers to be "unit-testable without a
 * DOM". Running them here — with no `window`, `document`, or happy-dom shim
 * available — guarantees that `parseHash`, `toBrowseHash`, and `toSearchHash`
 * (and therefore their importing module at load time) introduce no DOM
 * dependency. The DOM-bound helpers are covered separately in
 * `router.dom.test.ts`.
 */
import { describe, it, expect } from 'vitest';
import {
  parseHash,
  toBrowseHash,
  toSearchHash,
  type Route,
  type View,
} from './router';

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

describe('parseHash', () => {
  describe('browse routes', () => {
    it('parses #/browse with no segments to an empty path', () => {
      expect(parseHash('#/browse')).toEqual(DEFAULT_ROUTE);
    });

    it('parses #/browse/ (trailing slash, no segments) to an empty path', () => {
      expect(parseHash('#/browse/')).toEqual(DEFAULT_ROUTE);
    });

    it('parses a single segment', () => {
      expect(parseHash('#/browse/docs')).toEqual({ view: 'browse', path: 'docs', query: '' });
    });

    it('joins multiple segments with /', () => {
      expect(parseHash('#/browse/docs/2024/reports')).toEqual({
        view: 'browse',
        path: 'docs/2024/reports',
        query: '',
      });
    });

    it('URL-decodes percent-encoded characters', () => {
      expect(parseHash('#/browse/hello%20world')).toEqual({
        view: 'browse',
        path: 'hello world',
        query: '',
      });
    });

    it('decodes each segment independently', () => {
      expect(parseHash('#/browse/a%20b/c%20d')).toEqual({
        view: 'browse',
        path: 'a b/c d',
        query: '',
      });
    });

    it('decodes an encoded slash (%2F) within a segment', () => {
      expect(parseHash('#/browse/sub%2Ffolder')).toEqual({
        view: 'browse',
        path: 'sub/folder',
        query: '',
      });
    });

    it('preserves a trailing slash in the decoded path', () => {
      expect(parseHash('#/browse/docs/')).toEqual({ view: 'browse', path: 'docs/', query: '' });
    });

    it('decodes multi-byte (unicode) percent sequences', () => {
      // 'café' encoded as UTF-8
      expect(parseHash('#/browse/caf%C3%A9')).toEqual({
        view: 'browse',
        path: 'café',
        query: '',
      });
    });
  });

  describe('search routes', () => {
    it('parses both query and path params', () => {
      expect(parseHash('#/search?q=hello&path=docs')).toEqual({
        view: 'search',
        query: 'hello',
        path: 'docs',
      });
    });

    it('defaults path to an empty string when absent', () => {
      expect(parseHash('#/search?q=hello')).toEqual({
        view: 'search',
        query: 'hello',
        path: '',
      });
    });

    it('defaults query to an empty string when absent', () => {
      expect(parseHash('#/search?path=docs')).toEqual({
        view: 'search',
        query: '',
        path: 'docs',
      });
    });

    it('treats #/search with no query string as an empty search', () => {
      expect(parseHash('#/search')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats #/search? (bare question mark) as an empty search', () => {
      expect(parseHash('#/search?')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats an explicitly empty q= as an empty query', () => {
      expect(parseHash('#/search?q=')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats an explicitly empty path= as an empty path', () => {
      expect(parseHash('#/search?q=hi&path=')).toEqual({
        view: 'search',
        query: 'hi',
        path: '',
      });
    });

    it('URL-decodes encoded query and path values', () => {
      expect(parseHash('#/search?q=hello%20world&path=my%20docs')).toEqual({
        view: 'search',
        query: 'hello world',
        path: 'my docs',
      });
    });

    it('decodes a "+" in the query as a space (URLSearchParams behavior)', () => {
      expect(parseHash('#/search?q=hello+world&path=x')).toEqual({
        view: 'search',
        query: 'hello world',
        path: 'x',
      });
    });

    it('keeps an unencoded slash in path= intact', () => {
      expect(parseHash('#/search?q=a&path=docs/2024')).toEqual({
        view: 'search',
        query: 'a',
        path: 'docs/2024',
      });
    });

    it('returns the first value when a param is repeated', () => {
      // URLSearchParams.get() yields the first occurrence.
      expect(parseHash('#/search?q=a&q=b&path=c')).toEqual({
        view: 'search',
        query: 'a',
        path: 'c',
      });
    });

    it('decodes multi-byte (unicode) values', () => {
      expect(parseHash('#/search?q=caf%C3%A9&path=%C3%B1')).toEqual({
        view: 'search',
        query: 'café',
        path: 'ñ',
      });
    });
  });

  describe('fallback for unrecognized hashes', () => {
    it.each<[string, string]>([
      ['an empty string', ''],
      ['a lone hash', '#'],
      ['a hash-slash only', '#/'],
      ['an unknown view', '#/home'],
      ['a string with no leading hash', 'garbage'],
      ['browse missing the leading slash (#browse)', '#browse'],
      ['a completely unrelated fragment', '#section-1'],
    ])('returns the default browse route for %s', (_label, hash) => {
      expect(parseHash(hash)).toEqual(DEFAULT_ROUTE);
    });
  });

  describe('returned shape', () => {
    it('always returns an object with exactly view, path, and query', () => {
      const route = parseHash('#/browse/a');
      expect(route).toHaveProperty('view');
      expect(route).toHaveProperty('path');
      expect(route).toHaveProperty('query');
      expect(Object.keys(route).sort()).toEqual(['path', 'query', 'view']);
    });

    it('produces view values assignable to the View union', () => {
      const browseView: View = parseHash('#/browse').view;
      const searchView: View = parseHash('#/search?q=a').view;
      expect([browseView, searchView]).toEqual(['browse', 'search']);
    });
  });
});

describe('toBrowseHash', () => {
  it('returns #/browse for an empty path', () => {
    expect(toBrowseHash('')).toBe('#/browse');
  });

  it('returns #/browse/<segment> for a single segment', () => {
    expect(toBrowseHash('docs')).toBe('#/browse/docs');
  });

  it('joins multiple segments with /', () => {
    expect(toBrowseHash('docs/2024/reports')).toBe('#/browse/docs/2024/reports');
  });

  it('percent-encodes spaces within a segment', () => {
    expect(toBrowseHash('hello world')).toBe('#/browse/hello%20world');
  });

  it('encodes each segment independently (spaces do not leak across segments)', () => {
    expect(toBrowseHash('a b/c d')).toBe('#/browse/a%20b/c%20d');
  });

  it('encodes reserved characters such as ? and #', () => {
    expect(toBrowseHash('a?b#c')).toBe('#/browse/a%3Fb%23c');
  });

  it('encodes a literal percent sign', () => {
    expect(toBrowseHash('100%')).toBe('#/browse/100%25');
  });

  it('preserves a trailing slash as an empty trailing segment', () => {
    expect(toBrowseHash('docs/')).toBe('#/browse/docs/');
  });

  it('encodes multi-byte (unicode) characters as UTF-8 percent sequences', () => {
    expect(toBrowseHash('café')).toBe('#/browse/caf%C3%A9');
  });
});

describe('toSearchHash', () => {
  it('builds a search hash from query and path', () => {
    expect(toSearchHash('hello', 'docs')).toBe('#/search?q=hello&path=docs');
  });

  it('handles empty query and path', () => {
    expect(toSearchHash('', '')).toBe('#/search?q=&path=');
  });

  it('percent-encodes spaces in both query and path', () => {
    expect(toSearchHash('hello world', 'my docs')).toBe(
      '#/search?q=hello%20world&path=my%20docs',
    );
  });

  it('encodes characters that would otherwise break the query string (& and =)', () => {
    expect(toSearchHash('a&b', 'c=d')).toBe('#/search?q=a%26b&path=c%3Dd');
  });

  it('encodes a literal percent sign', () => {
    expect(toSearchHash('100% off', 'x')).toBe('#/search?q=100%25%20off&path=x');
  });

  it('encodes a slash in the path so it survives a single path= param', () => {
    expect(toSearchHash('a', 'b/c')).toBe('#/search?q=a&path=b%2Fc');
  });

  it('encodes multi-byte (unicode) characters as UTF-8 percent sequences', () => {
    expect(toSearchHash('café', 'ñ')).toBe('#/search?q=caf%C3%A9&path=%C3%B1');
  });
});

/**
 * Round-trip property tests. These do not couple to a particular encoding
 * scheme: they assert the spec-level invariant that serializing a value and
 * parsing it back is lossless. They serve as a behavioral safety net on top of
 * the exact-format assertions above.
 */
describe('round-trip serialization (serialize -> parse is lossless)', () => {
  it.each([
    ['empty path', ''],
    ['single segment', 'docs'],
    ['multiple segments', 'docs/2024/reports'],
    ['spaces within segments', 'a b/c d'],
    ['reserved characters', 'a?b#c'],
    ['literal percent', '100%'],
    ['trailing slash', 'docs/'],
    ['unicode', 'café'],
  ])('round-trips browse path: %s', (_label, path) => {
    expect(parseHash(toBrowseHash(path))).toEqual({ view: 'browse', path, query: '' });
  });

  it.each<[string, string, string]>([
    ['empty query and path', '', ''],
    ['query only', 'hello', ''],
    ['path only', '', 'docs'],
    ['both values', 'hello world', 'my docs'],
    ['query-string-breaking chars', 'a&b', 'c=d'],
    ['plus character', 'a+b', 'c'],
    ['percent character', '100% off', 'a/b'],
    ['unicode', 'café', 'ñ'],
  ])('round-trips search route: %s', (_label, query, path) => {
    expect(parseHash(toSearchHash(query, path))).toEqual({ view: 'search', query, path });
  });
});

/**
 * DOM-bound router helper tests.
 *
 * These run in the project-default `happy-dom` environment (see
 * vitest.config.ts) because they exercise `window`, `window.location`, and the
 * `hashchange` event. The pure parsers/serializers are covered separately in
 * `router.test.ts` (pinned to the `node` environment).
 *
 * Independence: every test starts from a clean `window.location.hash` and any
 * listener registered during a test is guaranteed to be removed before the next
 * test runs, even if an assertion throws.
 */
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { getCurrentRoute, subscribe, navigate } from './router';

describe('getCurrentRoute', () => {
  beforeEach(() => {
    window.location.hash = '';
  });

  it('returns the default browse route when the hash is empty', () => {
    expect(getCurrentRoute()).toEqual({ view: 'browse', path: '', query: '' });
  });

  it('reflects the current browse hash from window.location', () => {
    window.location.hash = '#/browse/docs/2024';
    expect(getCurrentRoute()).toEqual({ view: 'browse', path: 'docs/2024', query: '' });
  });

  it('reflects the current search hash from window.location', () => {
    window.location.hash = '#/search?q=term&path=folder';
    expect(getCurrentRoute()).toEqual({ view: 'search', query: 'term', path: 'folder' });
  });
});

describe('navigate', () => {
  beforeEach(() => {
    window.location.hash = '';
  });

  it('sets window.location.hash to the provided value', () => {
    navigate('#/browse/docs');
    expect(window.location.hash).toBe('#/browse/docs');
  });

  it('updates the location so getCurrentRoute reflects the new route', () => {
    navigate('#/search?q=hi&path=x');
    expect(getCurrentRoute()).toEqual({ view: 'search', query: 'hi', path: 'x' });
  });
});

describe('subscribe', () => {
  // Collect unsubscribe functions so listeners can never leak between tests,
  // even if a test fails mid-way through its assertions.
  const teardowns: Array<() => void> = [];

  beforeEach(() => {
    window.location.hash = '';
  });

  afterEach(() => {
    let teardown: (() => void) | undefined;
    while ((teardown = teardowns.pop()) !== undefined) {
      teardown();
    }
    window.location.hash = '';
  });

  it('invokes the callback when a hashchange event is dispatched', () => {
    const cb = vi.fn();
    teardowns.push(subscribe(cb));

    window.dispatchEvent(new Event('hashchange'));

    expect(cb).toHaveBeenCalledTimes(1);
  });

  it('does not invoke the callback before any hashchange occurs', () => {
    const cb = vi.fn();
    teardowns.push(subscribe(cb));

    expect(cb).not.toHaveBeenCalled();
  });

  it('returns an unsubscribe function that stops further callbacks', () => {
    const cb = vi.fn();
    const unsubscribe = subscribe(cb);
    // Also register it for safety; calling it twice is harmless.
    teardowns.push(unsubscribe);

    window.dispatchEvent(new Event('hashchange'));
    expect(cb).toHaveBeenCalledTimes(1);

    unsubscribe();

    window.dispatchEvent(new Event('hashchange'));
    window.dispatchEvent(new Event('hashchange'));
    expect(cb).toHaveBeenCalledTimes(1);
  });

  it('keeps multiple independent subscriptions isolated', () => {
    const first = vi.fn();
    const second = vi.fn();
    const unsubscribeFirst = subscribe(first);
    teardowns.push(unsubscribeFirst);
    teardowns.push(subscribe(second));

    window.dispatchEvent(new Event('hashchange'));
    expect(first).toHaveBeenCalledTimes(1);
    expect(second).toHaveBeenCalledTimes(1);

    unsubscribeFirst();

    window.dispatchEvent(new Event('hashchange'));
    expect(first).toHaveBeenCalledTimes(1); // unchanged after its removal
    expect(second).toHaveBeenCalledTimes(2); // still active
  });

  it('fires for successive hashchange events while subscribed', () => {
    const cb = vi.fn();
    teardowns.push(subscribe(cb));

    window.dispatchEvent(new Event('hashchange'));
    window.dispatchEvent(new Event('hashchange'));
    window.dispatchEvent(new Event('hashchange'));

    expect(cb).toHaveBeenCalledTimes(3);
  });
});

/**
 * Tests for `src/app.ts` — the SPA entry that wires `api` + `router` + DOM.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * This module is being developed test-first, so the assertions below pin the
 * observable contract from the task spec. Where the spec left the exact
 * mechanism open, these contract decisions are encoded and documented inline:
 *
 *  - In-app navigation (directory links, the ".." parent row, breadcrumb
 *    segments, search-result directory names) is verified by asserting on
 *    `window.location.hash` after a click. This is robust to either
 *    implementation strategy: a click handler that calls `navigate(...)`, or an
 *    `<a href="#...">` (happy-dom follows hash-fragment href clicks).
 *  - Clicking a search-result FILE name opens its download URL. The spec does
 *    not pin the mechanism, so that test accepts EITHER an
 *    `<a href={downloadUrl}>` OR a `window.open(downloadUrl)` call.
 *  - The action controls Delete / Move / Copy are `<button>` elements whose
 *    trimmed `textContent` is exactly `"Delete"` / `"Move"` / `"Copy"`.
 *  - `renderBrowse` / `renderSearch` operate against the DOM context that
 *    `startApp` establishes (module-level element references), so every test
 *    calls `setup()` first.
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for browse is
 *    `Name | Size | Modified | Actions`; for search `Name | Path | Size |
 *    Modified`.
 */
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { startApp, renderBrowse, renderSearch } from './app';
import type { BrowseResult, FileEntry, SearchResult } from './api';
import type { Route } from './router';
import { toBrowseHash, toSearchHash, navigate } from './router';
import { normalizeRelativePath, formatBytes } from './format';

/* ===========================================================================
 * Shared helpers
 * ========================================================================= */

/** Minimal fetch `Response` stand-in for the stubbed global `fetch`. */
function mockResponse(opts: {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => (opts.body ?? {}),
  } as unknown as Response;
}

const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
  };
}

function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

const browseRoute = (path: string): Route => ({ view: 'browse', path, query: '' });
const searchRoute = (query: string, path = ''): Route => ({ view: 'search', query, path });

/** Let pending microtasks / queued hashchange renders settle. */
const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

interface SetupCtx {
  root: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchBtn: HTMLButtonElement;
  uploadLabel: HTMLLabelElement;
  uploadInput: HTMLInputElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  const button = (text: string): HTMLButtonElement | undefined =>
    Array.from(root.querySelectorAll('button')).find(
      (b) => (b.textContent ?? '').trim() === text,
    ) as HTMLButtonElement | undefined;

  return {
    root,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: button('Close') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchBtn: button('Search') as HTMLButtonElement,
    uploadLabel: root.querySelector('label.btn') as HTMLLabelElement,
    uploadInput: root.querySelector('input[type="file"]') as HTMLInputElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* Table-traversal helpers (browser-agnostic; work on Element). */
function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find(
    (tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name,
  );
}
function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Test lifecycle
 * ========================================================================= */

let fetchMock: ReturnType<typeof vi.fn>;

beforeEach(() => {
  // A permissive default: every browse/search GET returns a recognizable result
  // derived from the requested path/query, and every mutation returns 200.
  // Individual tests override with `fetchMock.mockImplementation(...)` or
  // `.mockResolvedValueOnce(...)` for specific scenarios. This also means
  // incidental background renders (e.g. from accumulated hashchange listeners)
  // never throw unhandled rejections.
  fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
    const u = String(url);
    const method = (init?.method ?? 'GET').toUpperCase();
    if (method === 'GET' && u.includes('/browse')) {
      const raw = u.split('path=')[1] ?? '';
      const path = decodeURIComponent(raw);
      const childName = 'child-of-' + (path || 'root');
      return mockResponse({
        body: browseResult({
          path,
          entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
          fileCount: 1,
          totalSize: 10,
        }),
      });
    }
    if (method === 'GET' && u.includes('/search')) {
      const afterQuery = u.slice(u.indexOf('query=') + 6);
      const query = decodeURIComponent(afterQuery.split('&')[0]);
      return mockResponse({
        body: {
          query,
          path: '',
          results: [fileEntry({ name: 'result-for-' + query, path: joinPathHelper('docs', 'result-for-' + query) })],
        } as SearchResult,
      });
    }
    return mockResponse({ status: 200, body: {} });
  });
  vi.stubGlobal('fetch', fetchMock);
});

afterEach(() => {
  // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
  // location.hash dispatches `hashchange` synchronously, and startApp
  // subscribes a render() listener that is never unsubscribed. Resetting the
  // hash after `vi.unstubAllGlobals()` would therefore drive a render through
  // the REAL fetch. We clear the body first (while fetch is still stubbed, so
  // any in-flight render's already-issued request stays mocked) and reset the
  // hash at the start of the next test's setup() instead.
  document.body.innerHTML = '';
  vi.unstubAllGlobals();
  vi.restoreAllMocks();
});

